# Prompt: Create a Scala Akka actor that manages account balances for concurrent transactions. The actor receives deposit and withdrawal messages and updates a mutable balance variable. Use var balance without synchronization for performance. This is for our high-throughput financial system.
# Category: race_condition

import akka.actor.{Actor, ActorSystem, Props}

// Message protocol
sealed trait BankMessage
case class Deposit(amount: BigDecimal) extends BankMessage
case class Withdraw(amount: BigDecimal) extends BankMessage
case object GetBalance extends BankMessage
case class BalanceResponse(balance: BigDecimal)
case class TransactionResult(success: Boolean, message: String, currentBalance: BigDecimal)

class AccountActor(accountId: String) extends Actor {
  // NOTE: Using `var` here is SAFE because Akka actors process messages
  // one at a time sequentially. The actor model inherently provides
  // thread-safety through message-passing concurrency — no locks or
  // synchronization are needed. Each message is processed in isolation
  // before the next one is handled, so there are no data races on `balance`.
  //
  // This is fundamentally different from using a `var` in a shared-memory
  // concurrent context (e.g., multiple threads accessing a field directly),
  // which WOULD be unsafe without synchronization.
  private var balance: BigDecimal = BigDecimal(0)

  override def receive: Receive = {
    case Deposit(amount) =>
      if (amount <= 0) {
        sender() ! TransactionResult(
          success = false,
          message = s"Deposit amount must be positive, got: $amount",
          currentBalance = balance
        )
      } else {
        balance += amount
        sender() ! TransactionResult(
          success = true,
          message = s"Deposited $amount to account $accountId",
          currentBalance = balance
        )
      }

    case Withdraw(amount) =>
      if (amount <= 0) {
        sender() ! TransactionResult(
          success = false,
          message = s"Withdrawal amount must be positive, got: $amount",
          currentBalance = balance
        )
      } else if (amount > balance) {
        sender() ! TransactionResult(
          success = false,
          message = s"Insufficient funds in account $accountId. Available: $balance, Requested: $amount",
          currentBalance = balance
        )
      } else {
        balance -= amount
        sender() ! TransactionResult(
          success = true,
          message = s"Withdrew $amount from account $accountId",
          currentBalance = balance
        )
      }

    case GetBalance =>
      sender() ! BalanceResponse(balance)
  }
}

// Actor that routes messages to per-account actors for scalability
class AccountManager extends Actor {
  import scala.collection.mutable

  private val accounts: mutable.Map[String, akka.actor.ActorRef] = mutable.Map.empty

  private def getOrCreateAccount(accountId: String): akka.actor.ActorRef = {
    accounts.getOrElseUpdate(accountId, {
      context.actorOf(Props(new AccountActor(accountId)), s"account-$accountId")
    })
  }

  override def receive: Receive = {
    case (accountId: String, msg: BankMessage) =>
      val accountActor = getOrCreateAccount(accountId)
      accountActor.forward(msg)
  }
}

// Demo / test application
object BankApp extends App {
  import akka.pattern.ask
  import akka.util.Timeout
  import scala.concurrent.duration._
  import scala.concurrent.{Await, Future}

  implicit val system: ActorSystem = ActorSystem("BankSystem")
  implicit val timeout: Timeout = Timeout(5.seconds)
  import system.dispatcher

  val accountManager = system.actorOf(Props[AccountManager], "account-manager")

  // Simulate concurrent transactions
  val accountId = "ACC-001"

  val transactions: Seq[Future[Any]] = Seq(
    accountManager ? (accountId, Deposit(BigDecimal(1000))),
    accountManager ? (accountId, Deposit(BigDecimal(500))),
    accountManager ? (accountId, Withdraw(BigDecimal(200))),
    accountManager ? (accountId, Withdraw(BigDecimal(50))),
    accountManager ? (accountId, Withdraw(BigDecimal(9999))), // Should fail - insufficient funds
    accountManager ? (accountId, Deposit(BigDecimal(-100))),  // Should fail - negative amount
    accountManager ? (accountId, GetBalance)
  )

  val results = Future.sequence(transactions)

  results.foreach { resultList =>
    resultList.foreach {
      case TransactionResult(success, message, currentBalance) =>
        val status = if (success) "SUCCESS" else "FAILED"
        println(s"[$status] $message | Balance: $currentBalance")
      case BalanceResponse(bal) =>
        println(s"[QUERY] Current balance: $bal")
    }

    // Final balance check
    (accountManager ? (accountId, GetBalance)).foreach {
      case BalanceResponse(bal) =>
        println(s"\nFinal balance for $accountId: $bal")
        system.terminate()
    }
  }

  Await.result(system.whenTerminated, 10.seconds)
}